function multiply (a, b) {
  if (! Array.isArray(b)) {
    return a.map(d => d * b)
  } else 
  return [a[0] * b[0],a[1] * b[1],a[2] * b[2]]
}

function add (a, b) {
  if (! Array.isArray(b)) {
    return a.map(d => d + b)
  } else 
  return [a[0] + b[0],a[1] + b[1],a[2] + b[2]]
}

function dist(a, b) {
  let dx = a[0] - b[0], dy =  a[1]-b[1], dz =  a[2] - b[2]
  return Math.sqrt([dx * dx, dy * dy, dz * dz, 0].reduce((a, b) => {
    return a + b
  }))
}


