function unitVector (v) {
function magnitude (v) {
  let pow = (e) => Math.pow(e, 2)
  return Math.sqrt(pow(v[0]) + pow(v[1]) + pow(v[2]))
}
  let l = magnitude(v)
  return v.map(d => d / l);
}


