function makeVectorFieldGenericCool(cb, buffer ) {
  let w = width * 10, h = height * 10, zspace = 10;
  var result = buffer || []
  for (let i = 0; i < w; i++) {
    for (let j = 0; j < h; j++) {
      for (let k = 0; k < zspace; k++) {
      let [x, y, z] = clipSpace(i, j, k, w, h)

      let [x1, y1, z1] = zeroToOne(x , y, z) 
      //
      let idx = Math.round(x1 * w + y1 * w * h)
      
      result[idx] = cb(x, y, 0, i, j, k, idx)
      }
    }
  }
  return result
}

function makeVectorFieldGeneric2D(cb, buffer ) {
  let w = width * 10, h = height * 10;
  var result = buffer || []
  for (let i = 0; i < w; i++) {
    for (let j = 0; j < h; j++) {

      let [x, y, z] = clipSpace(i, j, 0, w, h)

      let [x1, y1, z1] = zeroToOne(x , y, 0) 
      //
      let idx = Math.round(x1 * w + y1 * w * h)
      
      result[idx] = cb(x, y, 0, i, j, k, idx)
   
    }
  }
  return result
}

function makeVectorFieldGeneric(cb, buffer ) {
  var result = buffer || []
  for (let i = 0; i < width; i++) {
    for (let j = 0; j < height; j++) {
      for (let k = 0; k < zspace; k++) {

      let [x, y, z] = clipSpace(k, j, i, width, height)

      let [x1, y1, z1] = zeroToOne(x , y, z) 
      //
      let idx = Math.round(x1 * width + y1 * width * height
         +  z1 * width * width * width 
         )
      
      result[idx] = cb(x, y, z, i, j, k, idx)
   
      }
    }
  }
  return result
}

