function findIndex (point) {
let [x, y, z] = point;
 var x1 = ((x + 1) /2).toPrecision(2)
  var y1 = ((1. - y) / 2).toPrecision(2) 
  var z1 = ((1. - z) / 2).toPrecision(2) 

  x1 *= 100;
  y1 *= 10000;
  z1 *= 1000000;

  return x1 + y1 + z1
}


function findPoint(d) {
  let [x, y, z] = d
  var x1 = ((x + 1) /2).toPrecision(2)
  var y1 = ((1. - y) / 2).toPrecision(2) 
  var z1 = ((1. - z) / 2).toPrecision(2) 

  x1 *= 100;
  y1 *= 10000;
  z1 *= 1000000;


  let index = Math.floor(x1 + y1 + z1);
  return [result[index], index, result]
}

