function makeVectorField2() {
    return makeVectorFieldGeneric(function (x,y,z) {
      let vec = [0,0,0,0]
      let p = [x ,y, 0]
      let l = circle(p);
      vec[0] = - x * 2
      vec[1] = - y * 2
  
      if (l < .6 && l > .3) {
        vec[0] = y * 10.
        vec[1] = -x * 10.
      } 
      vec[2] = sin(x)
      return vec
    })
}

